sql:
SELECT SUM(total_volume) AS TotalVolume
FROM batches
WHERE vineyard_id = 0 AND harvest_year = 2022;

SELECT v.vineyard_name, v.location, v.contact_email, v.total_acreage
FROM wine_samples AS ws
JOIN vineyards AS v ON ws.vineyard_id = v.vineyard_id;

SELECT sample_type, harvest_year
FROM wine_samples
ORDER BY harvest_year DESC;

SELECT AVG(average_sugar_content) AS average_sugar_content
FROM grape_varieties
WHERE region_id = 'Your_Specific_Region_Id';

external_knowledge:
- "birth dates" refers to the dates when the wine samples were taken (sample_date); 
- "ancestral homes" refers to the regions from which the wine samples originated (region_name); 
- "secrets of their creation" refers to the production methods used (method_name) and the grape varieties involved (variety_name).

sql:
SELECT variety_name, description
FROM grape_varieties
WHERE average_sugar_content = (
  SELECT MAX(average_sugar_content)
  FROM grape_varieties
);

SELECT variety_name, average_acidity, average_sugar_content
FROM grape_varieties
ORDER BY average_acidity DESC;

SELECT wine_samples.sample_id, wine_samples.sample_date, quality_assessments.quality_score 
FROM wine_samples
INNER JOIN quality_assessments ON wine_samples.sample_id = quality_assessments.sample_id;

SELECT * 
FROM wine_samples 
ORDER BY sample_date;
